import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  ToggleButton,
  ToggleButtonGroup,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Signup() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    mobile: "",
    role: "user",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(""); // UI error shown to user
  const [debugMsg, setDebugMsg] = useState(""); // optional debug line (can be removed later)

  // Keep behavior same — but ensure mobile stays string and maxLength
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((p) => ({ ...p, [name]: name === "mobile" ? value.replace(/\D/g, "") : value }));
  };

  const handleRoleChange = (event, newRole) => {
    if (newRole) setFormData((prev) => ({ ...prev, role: newRole.toLowerCase() }));
  };

  const validateMobile = (m) => /^[6-9]\d{9}$/.test(m);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setDebugMsg("");
    // Basic frontend validation
    if (!formData.fullName || !formData.email || !formData.mobile) {
      setError("Please fill Full name, Email and Mobile.");
      return;
    }
    if (!validateMobile(formData.mobile)) {
      setError("Mobile must be 10 digits and start with 6-9.");
      return;
    }

    setLoading(true);
    try {
      // Use full backend URL while debugging to avoid proxy confusion
      const url = "http://localhost:5000/api/auth/signup";

      console.log("➡️ SUBMIT signup to", url, "body:", formData);
      const res = await axios.post(url, formData, {
        headers: { "Content-Type": "application/json" },
        // timeout: 8000 // optional
      });

      console.log("⬅️ RESPONSE status:", res.status, "data:", res.data);
      if (res.data && res.data.success) {
        // success — redirect to login
        navigate("/login");
        return;
      }

      // If backend returned success:false
      const backendMsg = (res.data && res.data.message) || "Signup failed";
      setError(backendMsg);
      setDebugMsg(`status:${res.status}`);
    } catch (err) {
      // Show the most specific message available
      console.error("Signup error (frontend):", err);

      // axios error with response from server
      if (err.response && err.response.data) {
        // show backend message if present (handles 400/409/500)
        const backendMsg = err.response.data.message || JSON.stringify(err.response.data);
        setError(backendMsg);
        setDebugMsg(`status:${err.response.status}`);
        console.log("Backend response body:", err.response.data);
      } else if (err.request) {
        // request made but no response
        setError("No response from server. Make sure backend is running at http://localhost:5000");
        setDebugMsg("No response (network/CORS)");
        console.log("No response, request:", err.request);
      } else {
        // some other error
        setError("Signup error: " + err.message);
        setDebugMsg("Error thrown");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ padding: 4, marginTop: 5 }}>
        <Typography variant="h4" color="orange" align="center" gutterBottom>
          Rider App
        </Typography>
        <Typography variant="body1" align="center" gutterBottom>
          Create your account to get started
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Box component="form" onSubmit={handleSubmit} sx={{ mt: 2 }}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Email"
            name="email"
            type="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Mobile Number"
            name="mobile"
            type="tel"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          <Typography variant="subtitle1" sx={{ mt: 2 }}>Role</Typography>
          <ToggleButtonGroup
            value={formData.role}
            exclusive
            onChange={handleRoleChange}
            fullWidth
            sx={{ mb: 2 }}
          >
            <ToggleButton value="user">USER</ToggleButton>
            <ToggleButton value="owner">OWNER</ToggleButton>
          </ToggleButtonGroup>

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ bgcolor: "orange", "&:hover": { bgcolor: "#ff6600" } }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "REGISTER"}
          </Button>
        </Box>

        {/* debug helper — remove later */}
        {debugMsg && <Typography variant="caption" sx={{ mt: 1, display: "block", color: "gray" }}>{debugMsg}</Typography>}
      </Paper>
    </Container>
  );
}
